async (params, browser) => {
  // Open ESPN sport page
  await browser.open(`https://www.espn.com/${params.sport}/`)

  // Wait for news content
  await browser.waitForSelector('article, .contentItem, [class*=\'Story\'], h1, .content', 15000)

  // Let articles render
  await browser.wait(3000)

  // Scroll to load more articles
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract news articles
  const result = await browser.evaluate(`const articles = []; const seen = new Set(); document.querySelectorAll('article, .contentItem, [class*="Story"], [class*="ContentItem"]').forEach((el, i) => { if (articles.length < 15) { const titleEl = el.querySelector('h1 a, h2 a, h3 a, .contentItem__title a, [class*="title"] a'); const descEl = el.querySelector('p, .contentItem__subhead, [class*="description"]'); const linkEl = titleEl || el.querySelector('a[href*="/story/"], a[href*="/article/"]'); const title = titleEl?.textContent?.trim() || ''; const url = linkEl?.href || ''; if (title && !seen.has(title)) { seen.add(title); articles.push({ title: title, url: url, description: descEl?.textContent?.trim()?.slice(0, 200) || '' }); } } }); return { sport: params.sport, article_count: articles.length, articles: articles };`)

  return result
}
